class TransactionBuilder {
  constructor(dapp) {
    this.dapp = dapp;
    this.txParams = {};
  }

  setFunction(functionName, params) {
    this.txParams.functionName = functionName;
    this.txParams.params = params;
    return this;
  }

  setValue(value) {
    this.txParams.value = this.dapp.parseUnits(value.toString());
    return this;
  }

  setGasLimit(gasLimit) {
    this.txParams.gasLimit = BigInt(gasLimit);
    return this;
  }

  setGasPrice(gasPrice) {
    this.txParams.gasPrice = this.dapp.parseUnits(gasPrice.toString(), 'gwei');
    return this;
  }

  setNonce(nonce) {
    this.txParams.nonce = nonce;
    return this;
  }

  async build() {
    const { functionName, params, ...options } = this.txParams;
    return await this.dapp.buildTransaction(functionName, params, options);
  }

  async send() {
    const { functionName, params, ...options } = this.txParams;
    return await this.dapp.sendTransaction(functionName, params, options);
  }

  async estimateGas() {
    const { functionName, params, ...options } = this.txParams;
    return await this.dapp.estimateGas(functionName, params, options);
  }
}

